import React from "react"

class ClickButton extends React.Component {
    constructor() {
        super(props)
    }
    counter = 0
    render() {
        return (
            <button id="clickButton"> {this.counter} </button>
        )
    }
    onMouseClick() {
        this.counter++;
    }
}

export default ClickButton
